const html = $json.data || "";

const text = html.replace(/<[^>]*>/g," ").replace(/\s+/g," ");

const match = text.match(/Job Summary:(.*?)Similiar jobs/i);

const cleaned = match ? match[i].trim : text.substring(0,8000);

return [{
  cleaned_html: cleaned
}]

